using System.Collections.Generic;
using TMPro;
using UnityEngine;

/// <summary>
/// Roda de Itens (Tarefa #21 — "Roda de animais/itens"): UI radial que
/// aparece/desaparece ao premir o botão da Roda de Itens
/// (<see cref="PlayerInputRouter.ItemWheelPressed"/> — toggle), mostrando
/// todos os itens utilizáveis (<see cref="ItemData.usableByPlayer"/>) com
/// quantidade &gt; 0 no inventário (<see cref="PlayerProgress.inventory"/>).
///
/// - Navegação: analógico direito / D-pad
///   (<see cref="PlayerInputRouter.ItemNext"/>/<see cref="PlayerInputRouter.ItemPrev"/>)
///   move a selecção e EQUIPA imediatamente o item seleccionado
///   (<see cref="PlayerProgress.EquipItem"/> — "preview ao vivo": navegar já
///   troca o item activo, sem precisar de confirmar). Funciona tanto com a
///   roda aberta como fechada (troca rápida do item equipado sem abrir a
///   roda) — <see cref="PlayerInputRouter"/> só bloqueia esta navegação
///   enquanto a Roda de Formas estiver aberta.
/// - Usar o item equipado continua a ser feito fora da roda, com
///   <see cref="PlayerInputRouter.UseItemHold"/> (PlayerItemUser) — a roda só
///   troca QUAL item está equipado.
/// - Confirmação/cancelamento: como a troca já é aplicada ao navegar, abrir e
///   fechar a roda sem mover a selecção não tem qualquer efeito ("cancelar" =
///   não mover a selecção); fechar mantém o último item seleccionado equipado.
/// - Câmara lenta: Time.timeScale ≈ 0.2 enquanto a roda estiver aberta
///   (<see cref="WheelTimeScaleUtil"/>), partilhado com a Roda de Formas.
///
/// Montagem no Editor:
/// - "panelRoot": GameObject raiz da roda (activado/desactivado ao abrir/fechar).
/// - "wheelContainer": RectTransform vazio, centro da roda — os nós são
///   instanciados como filhos, posicionados em círculo.
/// - "nodePrefab": prefab com <see cref="ItemWheelNodeUI"/> (ícone + quantidade
///   + destaque + marcador "equipado").
/// - "itemNameText": TMP_Text opcional com o nome do item seleccionado.
/// </summary>
public class ItemWheelUI : MonoBehaviour
{
    [Header("Referências")]
    [SerializeField] private PlayerInputRouter input;

    [Header("UI")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private RectTransform wheelContainer;
    [SerializeField] private ItemWheelNodeUI nodePrefab;

    [Tooltip("Nome do item seleccionado (opcional).")]
    [SerializeField] private TMP_Text itemNameText;

    [Header("Layout (círculo)")]
    [SerializeField] private float radius = 180f;
    [Tooltip("Ângulo (graus) do primeiro nó, medido a partir do topo, sentido horário.")]
    [SerializeField] private float startAngleDeg = 0f;

    [Header("Câmara Lenta")]
    [Range(0.05f, 1f)]
    [SerializeField] private float slowTimeScale = 0.2f;

    private readonly List<ItemWheelNodeUI> _nodes = new List<ItemWheelNodeUI>();

    // Itens utilizáveis actualmente no inventário (reconstruída sempre que a
    // selecção muda ou a roda abre — inventário pequeno, custo desprezável).
    private readonly List<ItemData> _usableItems = new List<ItemData>();
    private readonly List<int> _usableQuantities = new List<int>();

    private int _selectedIndex;
    private bool _isOpen;

    private void Awake()
    {
        if (input == null) input = GetComponentInParent<PlayerInputRouter>();

        if (panelRoot != null) panelRoot.SetActive(false);
    }

    private void OnEnable()
    {
        if (input == null)
        {
            Debug.LogError("[ItemWheelUI] input não atribuído. Liga no Inspector.");
            enabled = false;
            return;
        }

        input.ItemWheelPressed += OnItemWheelPressed;
        input.ItemNext += OnItemNext;
        input.ItemPrev += OnItemPrev;
    }

    private void OnDisable()
    {
        if (input != null)
        {
            input.ItemWheelPressed -= OnItemWheelPressed;
            input.ItemNext -= OnItemNext;
            input.ItemPrev -= OnItemPrev;
        }

        // Salvaguarda: se este componente for desactivado enquanto a roda
        // estava aberta, garante que o modo de input e a câmara lenta não
        // ficam "pendurados".
        if (_isOpen)
        {
            WheelTimeScaleUtil.EndSlowdown();
            if (input != null) input.SetMode(PlayerInputRouter.InputMode.Gameplay);
            _isOpen = false;
        }
    }

    private void OnItemWheelPressed()
    {
        if (_isOpen)
            Close();
        else
            Open();
    }

    private void Open()
    {
        // Com a Roda de Formas aberta não faz sentido abrir também a Roda de
        // Itens (o Router já bloqueia ItemNext/Prev nesse modo).
        if (input.Mode == PlayerInputRouter.InputMode.FormWheel) return;

        _isOpen = true;
        input.SetMode(PlayerInputRouter.InputMode.ItemWheel);

        if (panelRoot != null) panelRoot.SetActive(true);

        RebuildUsableItems();
        SelectEquippedOrFirst();
        BuildNodes();
        RefreshNodes();

        WheelTimeScaleUtil.BeginSlowdown(slowTimeScale);
    }

    private void Close()
    {
        if (!_isOpen) return;
        _isOpen = false;

        input.SetMode(PlayerInputRouter.InputMode.Gameplay);

        if (panelRoot != null) panelRoot.SetActive(false);

        WheelTimeScaleUtil.EndSlowdown();
    }

    private void OnItemNext() => Navigate(+1);
    private void OnItemPrev() => Navigate(-1);

    /// <summary>
    /// Move a selecção (com ou sem a roda aberta) e equipa imediatamente o
    /// item seleccionado — ver resumo da classe ("preview ao vivo").
    /// </summary>
    private void Navigate(int direction)
    {
        RebuildUsableItems();
        if (_usableItems.Count == 0) return;

        // Garante que a selecção parte do item actualmente equipado, mesmo
        // que o inventário tenha mudado desde a última navegação (item
        // consumido, novo item recebido, etc.).
        SyncSelectionToEquipped();

        _selectedIndex = (_selectedIndex + direction + _usableItems.Count) % _usableItems.Count;
        EquipSelected();

        if (_isOpen)
        {
            BuildNodes();
            RefreshNodes();
        }
    }

    private void EquipSelected()
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || _usableItems.Count == 0) return;

        progress.EquipItem(_usableItems[_selectedIndex]);
    }

    /// <summary>Selecciona o item actualmente equipado, ou o primeiro utilizável se nenhum estiver equipado/o equipado não for utilizável.</summary>
    private void SelectEquippedOrFirst()
    {
        SyncSelectionToEquipped();
    }

    private void SyncSelectionToEquipped()
    {
        var progress = PlayerProgress.Instance;
        string equippedId = progress != null ? progress.equippedItemId : null;

        int idx = -1;
        for (int i = 0; i < _usableItems.Count; i++)
        {
            if (_usableItems[i] != null && _usableItems[i].itemId == equippedId)
            {
                idx = i;
                break;
            }
        }

        _selectedIndex = idx >= 0 ? idx : 0;
    }

    /// <summary>
    /// Reconstrói "_usableItems"/"_usableQuantities" a partir de
    /// PlayerProgress.inventory: apenas itens com ItemData.usableByPlayer ==
    /// true e quantidade &gt; 0 (resolvidos via GameDatabase).
    /// </summary>
    private void RebuildUsableItems()
    {
        _usableItems.Clear();
        _usableQuantities.Clear();

        var progress = PlayerProgress.Instance;
        var db = GameDatabase.Instance;
        if (progress == null || db == null) return;

        foreach (var entry in progress.inventory)
        {
            if (entry == null || entry.quantity <= 0) continue;

            var item = db.FindItem(entry.itemId);
            if (item == null || !item.usableByPlayer) continue;

            _usableItems.Add(item);
            _usableQuantities.Add(entry.quantity);
        }

        if (_selectedIndex >= _usableItems.Count)
            _selectedIndex = Mathf.Max(0, _usableItems.Count - 1);
    }

    /// <summary>
    /// (Re)cria um nó por item utilizável, posicionado em círculo
    /// ("wheelContainer" como centro). Chamado ao abrir a roda ou navegar — o
    /// número de itens utilizáveis pode ter mudado.
    /// </summary>
    private void BuildNodes()
    {
        if (!_isOpen || wheelContainer == null || nodePrefab == null) return;

        foreach (var node in _nodes)
            if (node != null) Destroy(node.gameObject);
        _nodes.Clear();

        int count = _usableItems.Count;
        if (count == 0) return;

        float stepDeg = 360f / count;

        for (int i = 0; i < count; i++)
        {
            var node = Instantiate(nodePrefab, wheelContainer);
            node.gameObject.SetActive(true);

            float angleDeg = startAngleDeg + stepDeg * i;
            float angleRad = angleDeg * Mathf.Deg2Rad;

            // Ângulo medido a partir do topo (0° = topo), sentido horário.
            Vector2 pos = new Vector2(Mathf.Sin(angleRad), Mathf.Cos(angleRad)) * radius;
            node.GetComponent<RectTransform>().anchoredPosition = pos;

            _nodes.Add(node);
        }
    }

    /// <summary>Actualiza cada nó (quantidade, destaque na selecção, marcador "equipado") e o nome do item seleccionado.</summary>
    private void RefreshNodes()
    {
        if (!_isOpen) return;

        var progress = PlayerProgress.Instance;
        string equippedId = progress != null ? progress.equippedItemId : null;

        for (int i = 0; i < _nodes.Count && i < _usableItems.Count; i++)
        {
            var item = _usableItems[i];
            bool isEquipped = item != null && item.itemId == equippedId;
            bool isSelected = i == _selectedIndex;

            _nodes[i].Setup(item, _usableQuantities[i], isEquipped, isSelected);
        }

        if (itemNameText != null)
        {
            var selected = _selectedIndex >= 0 && _selectedIndex < _usableItems.Count ? _usableItems[_selectedIndex] : null;
            itemNameText.text = selected != null ? selected.displayName : string.Empty;
        }
    }
}
